# ---------------------------------------------------------
# DATABASE FUNCTIONS
# ---------------------------------------------------------

def connect() -> sqlite3.Connection:
    connection = sqlite3.connect(DATABASE_FILE)
    connection.row_factory = sqlite3.Row
    return connection


def initialize_database() -> None:
    with connect() as connection:
        connection.execute(
            """
            CREATE TABLE IF NOT EXISTS tasks (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                subject TEXT NOT NULL,
                task_name TEXT NOT NULL,
                due_date TEXT NOT NULL,
                hours_needed REAL NOT NULL,
                studied_hours REAL NOT NULL DEFAULT 0,
                priority TEXT NOT NULL,
                completed INTEGER NOT NULL DEFAULT 0
            )
            """
        )

        task_columns = {
            row["name"]
            for row in connection.execute(
                "PRAGMA table_info(tasks)"
            ).fetchall()
        }

        if "studied_hours" not in task_columns:
            connection.execute(
                """
                ALTER TABLE tasks
                ADD COLUMN studied_hours REAL NOT NULL DEFAULT 0
                """
            )

        connection.execute(
            """
            CREATE TABLE IF NOT EXISTS availability (
                day_name TEXT PRIMARY KEY,
                study_hours REAL NOT NULL,
                start_time TEXT NOT NULL DEFAULT '16:00',
                end_time TEXT NOT NULL DEFAULT '18:00'
            )
            """
        )

        availability_columns = {
            row["name"]
            for row in connection.execute(
                "PRAGMA table_info(availability)"
            ).fetchall()
        }

        added_time_columns = False

        if "start_time" not in availability_columns:
            connection.execute(
                """
                ALTER TABLE availability
                ADD COLUMN start_time TEXT NOT NULL
                DEFAULT '16:00'
                """
            )
            added_time_columns = True

        if "end_time" not in availability_columns:
            connection.execute(
                """
                ALTER TABLE availability
                ADD COLUMN end_time TEXT NOT NULL
                DEFAULT '18:00'
                """
            )
            added_time_columns = True

        connection.execute(
            """
            CREATE TABLE IF NOT EXISTS availability_windows (
                day_name TEXT NOT NULL,
                slot_index INTEGER NOT NULL,
                start_time TEXT NOT NULL,
                end_time TEXT NOT NULL,
                PRIMARY KEY (day_name, slot_index)
            )
            """
        )

        connection.execute(
            """
            CREATE TABLE IF NOT EXISTS focus_sessions (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                task_id INTEGER NOT NULL,
                minutes INTEGER NOT NULL,
                completed_at TEXT NOT NULL
            )
            """
        )

        connection.execute(
            """
            CREATE TABLE IF NOT EXISTS settings (
                setting_key TEXT PRIMARY KEY,
                setting_value TEXT NOT NULL
            )
            """
        )

        connection.execute(
            """
            CREATE TABLE IF NOT EXISTS youtube_channels (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                channel_name TEXT NOT NULL,
                channel_reference TEXT NOT NULL UNIQUE,
                created_at TEXT NOT NULL
            )
            """
        )

        connection.execute(
            """
            CREATE TABLE IF NOT EXISTS study_resources (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                title TEXT NOT NULL,
                resource_url TEXT NOT NULL,
                category TEXT NOT NULL,
                notes TEXT NOT NULL DEFAULT '',
                created_at TEXT NOT NULL
            )
            """
        )

        for day_name in DAYS:
            is_weekend = day_name in {
                "Saturday",
                "Sunday",
            }
            default_hours = (
                3.0
                if is_weekend
                else 2.0
            )
            default_start = (
                "10:00"
                if is_weekend
                else "16:00"
            )
            default_end = (
                "13:00"
                if is_weekend
                else "18:00"
            )

            connection.execute(
                """
                INSERT OR IGNORE INTO availability (
                    day_name,
                    study_hours,
                    start_time,
                    end_time
                )
                VALUES (?, ?, ?, ?)
                """,
                (
                    day_name,
                    default_hours,
                    default_start,
                    default_end,
                ),
            )

        # Preserve hours from an older database by converting them
        # into a matching first start/end period.
        if added_time_columns:
            rows = connection.execute(
                """
                SELECT day_name, study_hours
                FROM availability
                """
            ).fetchall()

            for row in rows:
                is_weekend = row["day_name"] in {
                    "Saturday",
                    "Sunday",
                }
                start_value = (
                    time(10, 0)
                    if is_weekend
                    else time(16, 0)
                )
                start_dt = datetime.combine(
                    date.today(),
                    start_value,
                )
                end_dt = (
                    start_dt
                    + timedelta(
                        hours=max(
                            0.0,
                            float(row["study_hours"]),
                        )
                    )
                )

                connection.execute(
                    """
                    UPDATE availability
                    SET start_time = ?, end_time = ?
                    WHERE day_name = ?
                    """,
                    (
                        start_value.strftime("%H:%M"),
                        end_dt.time().strftime("%H:%M"),
                        row["day_name"],
                    ),
                )

        saved_window_count = connection.execute(
            """
            SELECT COUNT(*) AS window_count
            FROM availability_windows
            """
        ).fetchone()["window_count"]

        # Migrate each old one-period schedule into slot 0.
        if int(saved_window_count) == 0:
            legacy_rows = connection.execute(
                """
                SELECT
                    day_name,
                    study_hours,
                    start_time,
                    end_time
                FROM availability
                """
            ).fetchall()

            for row in legacy_rows:
                if float(row["study_hours"]) <= 0:
                    continue

                connection.execute(
                    """
                    INSERT OR IGNORE INTO availability_windows (
                        day_name,
                        slot_index,
                        start_time,
                        end_time
                    )
                    VALUES (?, 0, ?, ?)
                    """,
                    (
                        row["day_name"],
                        row["start_time"],
                        row["end_time"],
                    ),
                )

        connection.execute(
            """
            INSERT OR IGNORE INTO settings (
                setting_key,
                setting_value
            )
            VALUES ('daily_focus_goal', '60')
            """
        )





def add_task(
    subject: str,
    task_name: str,
    due_date_value: date,
    hours_needed: float,
    priority: str,
) -> None:
    with connect() as connection:
        connection.execute(
            """
            INSERT INTO tasks (
                subject,
                task_name,
                due_date,
                hours_needed,
                studied_hours,
                priority,
                completed
            )
            VALUES (?, ?, ?, ?, 0, ?, 0)
            """,
            (
                subject.strip(),
                task_name.strip(),
                due_date_value.isoformat(),
                float(hours_needed),
                priority,
            ),
        )


def get_tasks() -> list[dict]:
    with connect() as connection:
        rows = connection.execute(
            """
            SELECT *
            FROM tasks
            ORDER BY completed ASC, due_date ASC
            """
        ).fetchall()

    return [dict(row) for row in rows]


def get_task(task_id: int) -> dict | None:
    with connect() as connection:
        row = connection.execute(
            "SELECT * FROM tasks WHERE id = ?",
            (task_id,),
        ).fetchone()

    return dict(row) if row else None


def mark_complete(task_id: int) -> None:
    with connect() as connection:
        connection.execute(
            """
            UPDATE tasks
            SET completed = 1,
                studied_hours = hours_needed
            WHERE id = ?
            """,
            (task_id,),
        )


def reopen_task(task_id: int) -> None:
    task = get_task(task_id)
    if task is None:
        return

    studied_hours = float(task["studied_hours"])
    hours_needed = float(task["hours_needed"])

    if studied_hours >= hours_needed:
        studied_hours = max(0.0, hours_needed - 0.5)

    with connect() as connection:
        connection.execute(
            """
            UPDATE tasks
            SET completed = 0,
                studied_hours = ?
            WHERE id = ?
            """,
            (studied_hours, task_id),
        )


def update_task_progress(task_id: int, studied_hours: float) -> None:
    task = get_task(task_id)
    if task is None:
        return

    hours_needed = float(task["hours_needed"])
    safe_hours = max(0.0, min(float(studied_hours), hours_needed))
    completed = int(safe_hours >= hours_needed)

    with connect() as connection:
        connection.execute(
            """
            UPDATE tasks
            SET studied_hours = ?,
                completed = ?
            WHERE id = ?
            """,
            (safe_hours, completed, task_id),
        )


def delete_task(task_id: int) -> None:
    with connect() as connection:
        connection.execute(
            "DELETE FROM tasks WHERE id = ?",
            (task_id,),
        )


def availability_window_hours(
    day_settings: dict,
) -> float:
    if not day_settings.get("enabled", False):
        return 0.0

    total_hours = 0.0

    for window in day_settings.get("windows", []):
        start_value = time.fromisoformat(
            window["start"]
        )
        end_value = time.fromisoformat(
            window["end"]
        )

        start_dt = datetime.combine(
            date.today(),
            start_value,
        )
        end_dt = datetime.combine(
            date.today(),
            end_value,
        )

        total_hours += max(
            0.0,
            (
                end_dt - start_dt
            ).total_seconds() / 3600,
        )

    return total_hours



def get_availability() -> dict[str, dict]:
    with connect() as connection:
        day_rows = connection.execute(
            """
            SELECT
                day_name,
                study_hours,
                start_time,
                end_time
            FROM availability
            """
        ).fetchall()

        window_rows = connection.execute(
            """
            SELECT
                day_name,
                slot_index,
                start_time,
                end_time
            FROM availability_windows
            ORDER BY day_name, slot_index
            """
        ).fetchall()

    day_state = {
        row["day_name"]: dict(row)
        for row in day_rows
    }

    saved_windows: dict[str, list[dict]] = {
        day_name: []
        for day_name in DAYS
    }

    for row in window_rows:
        if row["day_name"] not in saved_windows:
            continue

        saved_windows[row["day_name"]].append(
            {
                "start": row["start_time"],
                "end": row["end_time"],
            }
        )

    result: dict[str, dict] = {}

    for day_name in DAYS:
        is_weekend = day_name in {
            "Saturday",
            "Sunday",
        }
        default_window = {
            "start": (
                "10:00"
                if is_weekend
                else "16:00"
            ),
            "end": (
                "13:00"
                if is_weekend
                else "18:00"
            ),
        }

        saved_day = day_state.get(day_name)

        if saved_day is None:
            result[day_name] = {
                "enabled": True,
                "windows": [default_window],
            }
            continue

        enabled = (
            float(saved_day["study_hours"]) > 0
        )
        windows = saved_windows.get(
            day_name,
            [],
        )

        # Compatibility fallback for a database that still only
        # contains the older single start/end columns.
        if enabled and not windows:
            windows = [
                {
                    "start": saved_day["start_time"],
                    "end": saved_day["end_time"],
                }
            ]

        if not windows:
            windows = [
                {
                    "start": (
                        saved_day["start_time"]
                        or default_window["start"]
                    ),
                    "end": (
                        saved_day["end_time"]
                        or default_window["end"]
                    ),
                }
            ]

        result[day_name] = {
            "enabled": enabled,
            "windows": windows,
        }

    return result



def save_availability(
    availability: dict[str, dict],
) -> None:
    with connect() as connection:
        for day_name, values in availability.items():
            enabled = bool(values["enabled"])
            windows = (
                values.get("windows", [])
                if enabled
                else []
            )

            sorted_windows = sorted(
                windows,
                key=lambda window: window["start"],
            )

            connection.execute(
                """
                DELETE FROM availability_windows
                WHERE day_name = ?
                """,
                (day_name,),
            )

            study_hours = 0.0

            for slot_index, window in enumerate(
                sorted_windows
            ):
                start_value = time.fromisoformat(
                    window["start"]
                )
                end_value = time.fromisoformat(
                    window["end"]
                )
                start_dt = datetime.combine(
                    date.today(),
                    start_value,
                )
                end_dt = datetime.combine(
                    date.today(),
                    end_value,
                )

                study_hours += max(
                    0.0,
                    (
                        end_dt - start_dt
                    ).total_seconds() / 3600,
                )

                connection.execute(
                    """
                    INSERT INTO availability_windows (
                        day_name,
                        slot_index,
                        start_time,
                        end_time
                    )
                    VALUES (?, ?, ?, ?)
                    """,
                    (
                        day_name,
                        slot_index,
                        window["start"],
                        window["end"],
                    ),
                )

            if sorted_windows:
                first_start = sorted_windows[0]["start"]
                last_end = sorted_windows[-1]["end"]
            else:
                is_weekend = day_name in {
                    "Saturday",
                    "Sunday",
                }
                first_start = (
                    "10:00"
                    if is_weekend
                    else "16:00"
                )
                last_end = (
                    "13:00"
                    if is_weekend
                    else "18:00"
                )

            connection.execute(
                """
                INSERT INTO availability (
                    day_name,
                    study_hours,
                    start_time,
                    end_time
                )
                VALUES (?, ?, ?, ?)
                ON CONFLICT(day_name)
                DO UPDATE SET
                    study_hours = excluded.study_hours,
                    start_time = excluded.start_time,
                    end_time = excluded.end_time
                """,
                (
                    day_name,
                    study_hours if enabled else 0.0,
                    first_start,
                    last_end,
                ),
            )



