def initialize_music_state() -> None:
    defaults = {
        "music_embed_url": "",
        "music_embed_error": "",
        "music_search_query": "",
        "music_search_results": [],
        "music_search_next_token": "",
        "music_search_total": 0,
        "music_search_error": "",
        "music_selected_index": 0,
        "music_persistence_enabled": False,
        "youtube_persistence_enabled": False,
        "persistent_music_url": "",
        "persistent_music_title": "",
        "persistent_music_active": False,
        "persistent_music_loop": False,
        "persistent_music_nonce": 0,
        "persistent_music_source_id": "",
        "uploaded_music_signature": "",
    }

    for key, value in defaults.items():
        if key not in st.session_state:
            st.session_state[key] = value





















def music_source_id(
    url: str,
    title: str,
) -> str:
    return hashlib.sha256(
        f"{url}|{title}".encode(
            "utf-8",
            errors="ignore",
        )
    ).hexdigest()


def remember_persistent_music(
    url: str,
    title: str,
    loop: bool = False,
) -> None:
    st.session_state.persistent_music_url = url
    st.session_state.persistent_music_title = title
    st.session_state.persistent_music_loop = loop
    st.session_state.persistent_music_source_id = (
        music_source_id(
            url,
            title,
        )
    )


def activate_persistent_music(
    url: str,
    title: str,
    loop: bool = False,
    force_reload: bool = False,
) -> None:
    new_source_id = music_source_id(
        url,
        title,
    )
    old_source_id = st.session_state.get(
        "persistent_music_source_id",
        "",
    )
    was_active = bool(
        st.session_state.get(
            "persistent_music_active",
            False,
        )
    )

    remember_persistent_music(
        url,
        title,
        loop=loop,
    )
    st.session_state.persistent_music_active = True

    if (
        force_reload
        or not was_active
        or new_source_id != old_source_id
    ):
        st.session_state.persistent_music_nonce += 1


def auto_activate_persistent_music(
    url: str,
    title: str,
    loop: bool = False,
) -> None:
    remember_persistent_music(
        url,
        title,
        loop=loop,
    )

    if st.session_state.music_persistence_enabled:
        activate_persistent_music(
            url,
            title,
            loop=loop,
        )


def stop_persistent_music() -> None:
    st.session_state.persistent_music_active = False
    st.session_state.persistent_music_nonce += 1


def uploaded_audio_to_data_url(
    uploaded_audio,
) -> tuple[str, str, str]:
    audio_bytes = uploaded_audio.getvalue()

    if not audio_bytes:
        raise ValueError(
            f"{uploaded_audio.name} is empty."
        )

    maximum_bytes = 25 * 1024 * 1024

    if len(audio_bytes) > maximum_bytes:
        raise ValueError(
            "Persistent uploaded audio must be "
            "25 MB or smaller."
        )

    mime_type = (
        uploaded_audio.type
        or "audio/mpeg"
    ).lower()

    allowed_types = {
        "audio/mpeg",
        "audio/mp3",
        "audio/wav",
        "audio/x-wav",
        "audio/ogg",
        "audio/mp4",
        "audio/x-m4a",
        "audio/aac",
        "audio/flac",
        "audio/x-flac",
    }

    if mime_type not in allowed_types:
        raise ValueError(
            f"{uploaded_audio.name} is not a "
            "supported audio format."
        )

    encoded = base64.b64encode(
        audio_bytes
    ).decode("ascii")

    return (
        uploaded_audio.name,
        f"data:{mime_type};base64,{encoded}",
        hashlib.sha256(
            audio_bytes
        ).hexdigest(),
    )


@st.cache_data
def generate_focus_noise_data_url(
    noise_type: str,
) -> str:
    if noise_type not in {
        "white",
        "brown",
    }:
        raise ValueError(
            "Unsupported focus sound."
        )

    sample_rate = 22050
    duration_seconds = 8
    sample_count = (
        sample_rate * duration_seconds
    )
    random_source = random.Random(
        2048
        if noise_type == "white"
        else 4096
    )

    frames = bytearray()
    last_output = 0.0

    for _ in range(sample_count):
        white_value = (
            random_source.random() * 2 - 1
        )

        if noise_type == "white":
            value = white_value * 0.22
        else:
            last_output = (
                last_output
                + 0.02 * white_value
            ) / 1.02
            value = last_output * 0.75

        value = max(
            -1.0,
            min(1.0, value),
        )
        frames.extend(
            struct.pack(
                "<h",
                int(value * 32767),
            )
        )

    audio_buffer = io.BytesIO()

    with wave.open(
        audio_buffer,
        "wb",
    ) as wav_file:
        wav_file.setnchannels(1)
        wav_file.setsampwidth(2)
        wav_file.setframerate(
            sample_rate
        )
        wav_file.writeframes(
            bytes(frames)
        )

    encoded = base64.b64encode(
        audio_buffer.getvalue()
    ).decode("ascii")

    return (
        "data:audio/wav;base64,"
        + encoded
    )


def persistent_music_embed_details(
    url: str,
) -> dict | None:
    if url.startswith("data:audio/"):
        return {
            "kind": "audio",
            "src": url,
            "height": 76,
            "label": "Audio player",
        }

    spotify_details = spotify_embed_details(
        url
    )

    if spotify_details:
        embed_url, player_height = (
            spotify_details
        )

        return {
            "kind": "iframe",
            "src": embed_url,
            "height": player_height,
            "label": "Spotify player",
        }

    youtube_details = youtube_embed_details(
        url
    )

    if youtube_details:
        content_type, embed_value = (
            youtube_details
        )

        if content_type == "playlist":
            separator = (
                "&"
                if "?" in embed_value
                else "?"
            )

            return {
                "kind": "iframe",
                "src": (
                    embed_value
                    + separator
                    + "autoplay=1&enablejsapi=1"
                ),
                "height": 220,
                "label": "YouTube playlist",
            }

        parsed = urllib.parse.urlparse(
            embed_value
        )
        video_id = urllib.parse.parse_qs(
            parsed.query
        ).get("v", [""])[0]

        if not video_id:
            return None

        return {
            "kind": "iframe",
            "src": (
                "https://www.youtube.com/embed/"
                f"{video_id}"
                "?autoplay=1&enablejsapi=1&playsinline=1"
            ),
            "height": 210,
            "label": "YouTube music",
        }

    if direct_audio_url(url):
        return {
            "kind": "audio",
            "src": url,
            "height": 76,
            "label": "Audio player",
        }

    return None


def render_persistent_music_overlay() -> None:
    """
    Render the persistent floating music player.

    The overlay is inserted into Streamlit's parent document so it stays
    visible during page navigation. Control handlers are rebound on every
    rerun because callbacks created by an older component iframe can stop
    working after that iframe is replaced.
    """

    initialize_music_state()

    persistence_enabled = bool(
        st.session_state.music_persistence_enabled
        or st.session_state.get(
            "youtube_persistence_enabled",
            False,
        )
    )
    active = (
        persistence_enabled
        and bool(
            st.session_state.persistent_music_active
        )
    )
    url = st.session_state.persistent_music_url
    title = (
        st.session_state.persistent_music_title
        or "StudyDragon Music"
    )
    loop_audio = bool(
        st.session_state.persistent_music_loop
    )
    nonce = int(
        st.session_state.persistent_music_nonce
    )

    details = (
        persistent_music_embed_details(url)
        if active and url
        else None
    )

    overlay_id = (
        "studyflow-persistent-music-overlay"
    )
    minimized_key = (
        "studyflowMusicOverlayMinimized"
    )
    position_key = (
        "studyflowMusicOverlayPosition"
    )
    closed_token_key = (
        "studyflowMusicOverlayClosedToken"
    )

    if details is None:
        components.html(
            f"""
            <script>
                try {{
                    const parentWindow = window.parent;
                    const parentDocument =
                        parentWindow.document;
                    const existing =
                        parentDocument.getElementById(
                            {json.dumps(overlay_id)}
                        );

                    if (existing) {{
                        existing.remove();
                    }}

                    parentWindow.localStorage.removeItem(
                        {json.dumps(closed_token_key)}
                    );
                }} catch (error) {{
                    console.warn(
                        "StudyDragon could not remove "
                        + "the music player.",
                        error
                    );
                }}
            </script>
            """,
            height=0,
            scrolling=False,
        )
        return

    source_id = (
        st.session_state.persistent_music_source_id
        or music_source_id(
            url,
            title,
        )
    )
    token = f"{source_id}|{nonce}"

    safe_title = html.escape(title)
    safe_src = html.escape(
        details["src"],
        quote=True,
    )
    safe_label = html.escape(
        details["label"],
        quote=True,
    )

    if details["kind"] == "audio":
        loop_attribute = (
            "loop"
            if loop_audio
            else ""
        )
        player_markup = f"""
            <audio
                class="sf-persistent-audio"
                controls
                autoplay
                {loop_attribute}
                style="width:100%;"
                src="{safe_src}">
            </audio>
        """
    else:
        player_markup = f"""
            <iframe
                class="sf-persistent-frame"
                src="{safe_src}"
                title="{safe_label}"
                allow="
                    autoplay;
                    encrypted-media;
                    picture-in-picture;
                    fullscreen
                "
                allowfullscreen
                style="
                    width:100%;
                    height:{int(details['height'])}px;
                    border:0;
                    border-radius:12px;
                    background:#000;
                ">
            </iframe>
        """

    overlay_script = f"""
    <script>
        (() => {{
            try {{
                const parentWindow = window.parent;
                const doc = parentWindow.document;
                const overlayId =
                    {json.dumps(overlay_id)};
                const token =
                    {json.dumps(token)};
                const minimizedKey =
                    {json.dumps(minimized_key)};
                const positionKey =
                    {json.dumps(position_key)};
                const closedTokenKey =
                    {json.dumps(closed_token_key)};
                const titleText =
                    {json.dumps(title)};

                let overlay =
                    doc.getElementById(overlayId);

                if (
                    overlay
                    && overlay.dataset.token !== token
                ) {{
                    overlay.remove();
                    overlay = null;
                    parentWindow.localStorage.removeItem(
                        closedTokenKey
                    );
                }}

                const closedToken =
                    parentWindow.localStorage.getItem(
                        closedTokenKey
                    );

                if (
                    !overlay
                    && closedToken === token
                ) {{
                    return;
                }}

                if (!overlay) {{
                    overlay =
                        doc.createElement("section");
                    overlay.id = overlayId;
                    overlay.dataset.token = token;
                    overlay.dataset.minimized =
                        parentWindow.localStorage.getItem(
                            minimizedKey
                        ) === "true"
                        ? "true"
                        : "false";

                    overlay.innerHTML = `
                        <div class="sf-music-header">
                            <div class="sf-music-name">
                                <span
                                    class="sf-music-icon"
                                    aria-hidden="true">
                                    ♫
                                </span>
                                <strong
                                    class="sf-music-title">
                                    {safe_title}
                                </strong>
                            </div>

                            <div class="sf-music-actions">
                                <button
                                    class="sf-minimize"
                                    type="button"
                                    aria-label="Minimize player"
                                    title="Minimize player">
                                    −
                                </button>

                                <button
                                    class="sf-close"
                                    type="button"
                                    aria-label="Close player"
                                    title="Close player">
                                    ×
                                </button>
                            </div>
                        </div>

                        <div class="sf-music-body">
                            {player_markup}
                        </div>
                    `;

                    doc.body.appendChild(overlay);

                    try {{
                        const savedPosition =
                            JSON.parse(
                                parentWindow.localStorage
                                .getItem(positionKey)
                                || "null"
                            );

                        if (
                            savedPosition
                            && Number.isFinite(
                                savedPosition.left
                            )
                            && Number.isFinite(
                                savedPosition.top
                            )
                        ) {{
                            const maxLeft = Math.max(
                                0,
                                doc.documentElement
                                .clientWidth
                                - overlay.offsetWidth
                            );
                            const maxTop = Math.max(
                                0,
                                doc.documentElement
                                .clientHeight
                                - overlay.offsetHeight
                            );

                            overlay.style.right = "auto";
                            overlay.style.bottom = "auto";
                            overlay.style.left =
                                `${{Math.max(
                                    0,
                                    Math.min(
                                        maxLeft,
                                        savedPosition.left
                                    )
                                )}}px`;
                            overlay.style.top =
                                `${{Math.max(
                                    0,
                                    Math.min(
                                        maxTop,
                                        savedPosition.top
                                    )
                                )}}px`;
                        }}
                    }} catch (error) {{
                        parentWindow.localStorage.removeItem(
                            positionKey
                        );
                    }}
                }} else {{
                    const titleElement =
                        overlay.querySelector(
                            ".sf-music-title"
                        );

                    if (titleElement) {{
                        titleElement.textContent =
                            titleText;
                    }}
                }}

                const styleId =
                    "studyflow-reliable-music-style";

                if (!doc.getElementById(styleId)) {{
                    const style =
                        doc.createElement("style");
                    style.id = styleId;
                    style.textContent = `
                        #${{overlayId}} {{
                            position: fixed;
                            right: 22px;
                            bottom: 22px;
                            width: min(
                                390px,
                                calc(100vw - 32px)
                            );
                            z-index: 2147483000;
                            overflow: hidden;
                            border: 1px solid
                                var(--border-strong);
                            border-radius: 18px;
                            color: var(--text);
                            background: var(--card-alt);
                            box-shadow:
                                0 20px 60px
                                rgba(0,0,0,0.48);
                            font-family:
                                Arial,
                                Helvetica,
                                sans-serif;
                            transition:
                                width 150ms ease,
                                box-shadow 150ms ease;
                        }}

                        #${{overlayId}}
                        .sf-music-header {{
                            display: flex;
                            align-items: center;
                            justify-content:
                                space-between;
                            gap: 10px;
                            min-height: 52px;
                            padding: 9px 11px;
                            cursor: move;
                            user-select: none;
                            touch-action: none;
                            background:
                                linear-gradient(
                                    135deg,
                                    var(--accent),
                                    var(--accent-hover)
                                );
                        }}

                        #${{overlayId}}
                        .sf-music-name {{
                            display: flex;
                            align-items: center;
                            gap: 8px;
                            min-width: 0;
                            overflow: hidden;
                        }}

                        #${{overlayId}}
                        .sf-music-icon {{
                            display: inline-flex;
                            align-items: center;
                            justify-content: center;
                            width: 30px;
                            height: 30px;
                            flex: 0 0 auto;
                            border-radius: 9px;
                            color: var(--accent-text);
                            background: var(--card);
                            font-weight: 900;
                        }}

                        #${{overlayId}}
                        .sf-music-title {{
                            overflow: hidden;
                            color: var(--accent-text);
                            font-size: 14px;
                            text-overflow:
                                ellipsis;
                            white-space: nowrap;
                        }}

                        #${{overlayId}}
                        .sf-music-actions {{
                            display: flex;
                            gap: 7px;
                            flex: 0 0 auto;
                        }}

                        #${{overlayId}}
                        .sf-music-actions button {{
                            display: inline-flex;
                            align-items: center;
                            justify-content: center;
                            width: 34px;
                            height: 34px;
                            padding: 0;
                            border: 1px solid
                                rgba(255,255,255,0.38);
                            border-radius: 999px;
                            color: var(--accent-text);
                            background:
                                rgba(0,0,0,0.2);
                            font-size: 20px;
                            font-weight: 900;
                            line-height: 1;
                            cursor: pointer;
                            touch-action: manipulation;
                            -webkit-tap-highlight-color:
                                transparent;
                        }}

                        #${{overlayId}}
                        .sf-music-actions button:hover,
                        #${{overlayId}}
                        .sf-music-actions button:focus-visible {{
                            outline: none;
                            background: var(--card-hover);
                            border-color: var(--border-strong);
                        }}

                        #${{overlayId}}
                        .sf-music-body {{
                            padding: 11px;
                            background: var(--card-alt);
                        }}

                        #${{overlayId}}.minimized {{
                            width: min(
                                315px,
                                calc(100vw - 32px)
                            );
                        }}

                        #${{overlayId}}.minimized
                        .sf-music-body {{
                            display: none;
                        }}

                        #${{overlayId}}.sf-dragging {{
                            transition: none;
                            box-shadow:
                                0 26px 75px
                                rgba(0,0,0,0.58);
                        }}

                        @media (max-width: 650px) {{
                            #${{overlayId}} {{
                                right: 12px;
                                bottom: 12px;
                                width:
                                    calc(100vw - 24px);
                            }}

                            #${{overlayId}}.minimized {{
                                width:
                                    calc(100vw - 24px);
                            }}
                        }}
                    `;

                    doc.head.appendChild(style);
                }}

                /*
                 * Rebind every handler on every Streamlit rerun.
                 * Using on... properties replaces stale handlers
                 * instead of stacking duplicate listeners.
                 */
                const header =
                    overlay.querySelector(
                        ".sf-music-header"
                    );
                const minimizeButton =
                    overlay.querySelector(
                        ".sf-minimize"
                    );
                const closeButton =
                    overlay.querySelector(
                        ".sf-close"
                    );

                const applyMinimizedState = () => {{
                    const minimized =
                        overlay.dataset.minimized
                        === "true";

                    overlay.classList.toggle(
                        "minimized",
                        minimized
                    );

                    minimizeButton.textContent =
                        minimized
                        ? "+"
                        : "−";
                    minimizeButton.setAttribute(
                        "aria-label",
                        minimized
                        ? "Maximize player"
                        : "Minimize player"
                    );
                    minimizeButton.title =
                        minimized
                        ? "Maximize player"
                        : "Minimize player";
                }};

                applyMinimizedState();

                minimizeButton.onpointerdown = (
                    event
                ) => {{
                    event.stopPropagation();
                }};

                minimizeButton.onclick = (
                    event
                ) => {{
                    event.preventDefault();
                    event.stopPropagation();

                    const nextValue =
                        overlay.dataset.minimized
                        !== "true";

                    overlay.dataset.minimized =
                        nextValue
                        ? "true"
                        : "false";

                    parentWindow.localStorage.setItem(
                        minimizedKey,
                        nextValue
                        ? "true"
                        : "false"
                    );

                    applyMinimizedState();
                }};

                closeButton.onpointerdown = (
                    event
                ) => {{
                    event.stopPropagation();
                }};

                closeButton.onclick = (
                    event
                ) => {{
                    event.preventDefault();
                    event.stopPropagation();

                    parentWindow.localStorage.setItem(
                        closedTokenKey,
                        token
                    );
                    overlay.remove();
                }};

                let dragging = false;
                let pointerId = null;
                let startX = 0;
                let startY = 0;
                let startLeft = 0;
                let startTop = 0;

                const finishDrag = (
                    event
                ) => {{
                    if (!dragging) {{
                        return;
                    }}

                    dragging = false;
                    overlay.classList.remove(
                        "sf-dragging"
                    );

                    try {{
                        if (
                            pointerId !== null
                            && header.hasPointerCapture(
                                pointerId
                            )
                        ) {{
                            header.releasePointerCapture(
                                pointerId
                            );
                        }}
                    }} catch (error) {{
                        // Pointer capture may already be gone.
                    }}

                    const rectangle =
                        overlay.getBoundingClientRect();

                    parentWindow.localStorage.setItem(
                        positionKey,
                        JSON.stringify({{
                            left: rectangle.left,
                            top: rectangle.top,
                        }})
                    );

                    pointerId = null;
                }};

                header.onpointerdown = (
                    event
                ) => {{
                    if (
                        event.button !== 0
                        || event.target.closest(
                            "button"
                        )
                    ) {{
                        return;
                    }}

                    event.preventDefault();

                    dragging = true;
                    pointerId =
                        event.pointerId;

                    const rectangle =
                        overlay.getBoundingClientRect();

                    startX = event.clientX;
                    startY = event.clientY;
                    startLeft =
                        rectangle.left;
                    startTop =
                        rectangle.top;

                    overlay.style.right = "auto";
                    overlay.style.bottom = "auto";
                    overlay.style.left =
                        `${{startLeft}}px`;
                    overlay.style.top =
                        `${{startTop}}px`;

                    overlay.classList.add(
                        "sf-dragging"
                    );

                    try {{
                        header.setPointerCapture(
                            pointerId
                        );
                    }} catch (error) {{
                        // Dragging still works on most browsers.
                    }}
                }};

                header.onpointermove = (
                    event
                ) => {{
                    if (
                        !dragging
                        || event.pointerId
                        !== pointerId
                    ) {{
                        return;
                    }}

                    const maxLeft = Math.max(
                        0,
                        doc.documentElement
                        .clientWidth
                        - overlay.offsetWidth
                    );
                    const maxTop = Math.max(
                        0,
                        doc.documentElement
                        .clientHeight
                        - overlay.offsetHeight
                    );

                    const nextLeft =
                        startLeft
                        + event.clientX
                        - startX;
                    const nextTop =
                        startTop
                        + event.clientY
                        - startY;

                    overlay.style.left =
                        `${{Math.max(
                            0,
                            Math.min(
                                maxLeft,
                                nextLeft
                            )
                        )}}px`;
                    overlay.style.top =
                        `${{Math.max(
                            0,
                            Math.min(
                                maxTop,
                                nextTop
                            )
                        )}}px`;
                }};

                header.onpointerup =
                    finishDrag;
                header.onpointercancel =
                    finishDrag;
                header.onlostpointercapture =
                    finishDrag;

                parentWindow.onresize = () => {{
                    const rectangle =
                        overlay.getBoundingClientRect();
                    const maxLeft = Math.max(
                        0,
                        doc.documentElement
                        .clientWidth
                        - overlay.offsetWidth
                    );
                    const maxTop = Math.max(
                        0,
                        doc.documentElement
                        .clientHeight
                        - overlay.offsetHeight
                    );

                    if (
                        rectangle.left > maxLeft
                        || rectangle.top > maxTop
                    ) {{
                        overlay.style.right = "auto";
                        overlay.style.bottom = "auto";
                        overlay.style.left =
                            `${{Math.max(
                                0,
                                Math.min(
                                    maxLeft,
                                    rectangle.left
                                )
                            )}}px`;
                        overlay.style.top =
                            `${{Math.max(
                                0,
                                Math.min(
                                    maxTop,
                                    rectangle.top
                                )
                            )}}px`;
                    }}
                }};
            }} catch (error) {{
                console.warn(
                    "StudyDragon could not create "
                    + "the music player.",
                    error
                );
            }}
        }})();
    </script>
    """

    components.html(
        overlay_script,
        height=0,
        scrolling=False,
    )





def normalize_music_url(url: str) -> str:
    clean_url = url.strip()

    if not clean_url:
        return ""

    if not clean_url.startswith(
        ("http://", "https://")
    ):
        clean_url = "https://" + clean_url

    return clean_url


def spotify_embed_details(
    url: str,
) -> tuple[str, int] | None:
    try:
        parsed = urllib.parse.urlparse(url)
    except ValueError:
        return None

    hostname = parsed.netloc.lower()

    if hostname not in {
        "open.spotify.com",
        "www.open.spotify.com",
    }:
        return None

    path_parts = [
        part
        for part in parsed.path.split("/")
        if part
    ]

    if len(path_parts) < 2:
        return None

    item_type = path_parts[0].lower()
    item_id = path_parts[1]

    supported_types = {
        "track",
        "album",
        "playlist",
        "artist",
        "show",
        "episode",
    }

    if (
        item_type not in supported_types
        or not re.fullmatch(
            r"[A-Za-z0-9]+",
            item_id,
        )
    ):
        return None

    embed_url = (
        "https://open.spotify.com/embed/"
        f"{item_type}/{item_id}"
        "?utm_source=generator&theme=0"
    )

    compact_types = {
        "track",
        "episode",
    }
    player_height = (
        176
        if item_type in compact_types
        else 420
    )

    return embed_url, player_height


def youtube_embed_details(
    url: str,
) -> tuple[str, str] | None:
    try:
        parsed = urllib.parse.urlparse(url)
    except ValueError:
        return None

    hostname = parsed.netloc.lower().replace(
        "www.",
        "",
    )
    query = urllib.parse.parse_qs(
        parsed.query
    )

    if hostname == "youtu.be":
        video_id = parsed.path.strip("/")

        if re.fullmatch(
            r"[A-Za-z0-9_-]{6,}",
            video_id,
        ):
            return "video", (
                "https://www.youtube.com/watch"
                f"?v={video_id}"
            )

        return None

    if hostname not in {
        "youtube.com",
        "music.youtube.com",
        "m.youtube.com",
    }:
        return None

    playlist_id = query.get("list", [""])[0]
    video_id = query.get("v", [""])[0]

    if (
        parsed.path == "/playlist"
        and re.fullmatch(
            r"[A-Za-z0-9_-]{6,}",
            playlist_id,
        )
    ):
        return "playlist", (
            "https://www.youtube.com/embed/"
            "videoseries"
            f"?list={playlist_id}"
        )

    if (
        parsed.path == "/watch"
        and re.fullmatch(
            r"[A-Za-z0-9_-]{6,}",
            video_id,
        )
    ):
        return "video", (
            "https://www.youtube.com/watch"
            f"?v={video_id}"
        )

    if parsed.path.startswith("/shorts/"):
        short_id = parsed.path.split(
            "/shorts/",
            1,
        )[1].split("/", 1)[0]

        if re.fullmatch(
            r"[A-Za-z0-9_-]{6,}",
            short_id,
        ):
            return "video", (
                "https://www.youtube.com/watch"
                f"?v={short_id}"
            )

    return None


def direct_audio_url(
    url: str,
) -> bool:
    try:
        path = urllib.parse.urlparse(
            url
        ).path.lower()
    except ValueError:
        return False

    return path.endswith(
        (
            ".mp3",
            ".wav",
            ".ogg",
            ".m4a",
            ".aac",
            ".flac",
        )
    )


def render_music_from_url(
    url: str,
) -> bool:
    spotify_details = spotify_embed_details(
        url
    )

    if spotify_details:
        embed_url, player_height = (
            spotify_details
        )
        safe_embed_url = html.escape(
            embed_url,
            quote=True,
        )

        components.html(
            f"""
            <iframe
                style="
                    border-radius:14px;
                    border:0;
                    width:100%;
                "
                src="{safe_embed_url}"
                height="{player_height}"
                allow="
                    autoplay;
                    clipboard-write;
                    encrypted-media;
                    fullscreen;
                    picture-in-picture
                "
                loading="lazy">
            </iframe>
            """,
            height=player_height + 8,
            scrolling=False,
        )
        return True

    youtube_details = youtube_embed_details(
        url
    )

    if youtube_details:
        content_type, embed_value = (
            youtube_details
        )

        if content_type == "playlist":
            safe_embed_url = html.escape(
                embed_value,
                quote=True,
            )
            components.html(
                f"""
                <iframe
                    style="
                        border-radius:14px;
                        border:0;
                        width:100%;
                        aspect-ratio:16/9;
                    "
                    src="{safe_embed_url}"
                    title="YouTube music playlist"
                    allow="
                        accelerometer;
                        autoplay;
                        clipboard-write;
                        encrypted-media;
                        gyroscope;
                        picture-in-picture;
                        web-share
                    "
                    allowfullscreen>
                </iframe>
                """,
                height=510,
                scrolling=False,
            )
        else:
            st.video(embed_value)

        return True

    if direct_audio_url(url):
        st.audio(url)
        return True

    return False


def render_focus_sound_generator(
    theme_name: str,
) -> None:
    is_dark = theme_name == "Dark"
    page = "#071416" if is_dark else "#f8fbfa"
    card = "#10272b" if is_dark else "#ffffff"
    text = "#f4fbfa" if is_dark else "#153a3d"
    soft = "#b8ccca" if is_dark else "#4e696b"
    border = (
        "rgba(144,205,200,0.28)"
        if is_dark
        else "rgba(39,91,88,0.24)"
    )

    components.html(
        f"""
        <!DOCTYPE html>
        <html>
        <head>
            <style>
                * {{
                    box-sizing: border-box;
                }}

                body {{
                    margin: 0;
                    padding: 0;
                    color: {text};
                    background: transparent;
                    font-family:
                        Arial,
                        Helvetica,
                        sans-serif;
                }}

                .sound-card {{
                    border: 1px solid {border};
                    border-radius: 16px;
                    padding: 1rem;
                    background: {card};
                }}

                .sound-title {{
                    font-size: 1rem;
                    font-weight: 800;
                    margin-bottom: 0.25rem;
                }}

                .sound-help {{
                    color: {soft};
                    font-size: 0.82rem;
                    line-height: 1.4;
                    margin-bottom: 0.8rem;
                }}

                .controls {{
                    display: grid;
                    grid-template-columns:
                        repeat(3, minmax(0, 1fr));
                    gap: 0.6rem;
                }}

                button {{
                    border: 1px solid {border};
                    border-radius: 999px;
                    padding: 0.65rem 0.75rem;
                    color: {text};
                    background: {page};
                    font-weight: 750;
                    cursor: pointer;
                }}

                button:hover {{
                    border-color: #2dd4bf;
                }}

                .active {{
                    color: #032421;
                    background: #2dd4bf;
                    border-color: #2dd4bf;
                }}

                .volume-row {{
                    display: grid;
                    grid-template-columns:
                        auto 1fr auto;
                    gap: 0.7rem;
                    align-items: center;
                    margin-top: 0.9rem;
                    color: {soft};
                    font-size: 0.82rem;
                }}

                input[type="range"] {{
                    width: 100%;
                }}
            </style>
        </head>
        <body>
            <div class="sound-card">
                <div class="sound-title">
                    Browser focus sounds
                </div>
                <div class="sound-help">
                    Generate steady background noise without
                    loading an external song or playlist.
                </div>

                <div class="controls">
                    <button id="whiteButton"
                            onclick="toggleNoise('white')">
                        White noise
                    </button>
                    <button id="brownButton"
                            onclick="toggleNoise('brown')">
                        Brown noise
                    </button>
                    <button id="stopButton"
                            onclick="stopNoise()">
                        Stop
                    </button>
                </div>

                <div class="volume-row">
                    <span>Quiet</span>
                    <input
                        id="volume"
                        type="range"
                        min="0"
                        max="0.35"
                        step="0.01"
                        value="0.08"
                        oninput="updateVolume(this.value)"
                    >
                    <span>Loud</span>
                </div>
            </div>

            <script>
                let audioContext = null;
                let sourceNode = null;
                let gainNode = null;
                let currentType = null;

                function ensureContext() {{
                    if (!audioContext) {{
                        audioContext = new (
                            window.AudioContext
                            || window.webkitAudioContext
                        )();
                    }}

                    if (
                        audioContext.state === "suspended"
                    ) {{
                        audioContext.resume();
                    }}
                }}

                function createNoiseBuffer(type) {{
                    const length =
                        audioContext.sampleRate * 4;
                    const buffer =
                        audioContext.createBuffer(
                            1,
                            length,
                            audioContext.sampleRate
                        );
                    const data =
                        buffer.getChannelData(0);

                    if (type === "white") {{
                        for (
                            let index = 0;
                            index < length;
                            index++
                        ) {{
                            data[index] =
                                Math.random() * 2 - 1;
                        }}
                    }} else {{
                        let lastOutput = 0;

                        for (
                            let index = 0;
                            index < length;
                            index++
                        ) {{
                            const white =
                                Math.random() * 2 - 1;
                            lastOutput =
                                (
                                    lastOutput
                                    + 0.02 * white
                                )
                                / 1.02;
                            data[index] =
                                lastOutput * 3.5;
                        }}
                    }}

                    return buffer;
                }}

                function updateButtons() {{
                    document
                        .getElementById("whiteButton")
                        .classList.toggle(
                            "active",
                            currentType === "white"
                        );
                    document
                        .getElementById("brownButton")
                        .classList.toggle(
                            "active",
                            currentType === "brown"
                        );
                }}

                function startNoise(type) {{
                    ensureContext();
                    stopNoise(false);

                    sourceNode =
                        audioContext.createBufferSource();
                    sourceNode.buffer =
                        createNoiseBuffer(type);
                    sourceNode.loop = true;

                    gainNode =
                        audioContext.createGain();
                    gainNode.gain.value = Number(
                        document.getElementById(
                            "volume"
                        ).value
                    );

                    sourceNode.connect(gainNode);
                    gainNode.connect(
                        audioContext.destination
                    );
                    sourceNode.start();

                    currentType = type;
                    updateButtons();
                }}

                function toggleNoise(type) {{
                    if (currentType === type) {{
                        stopNoise();
                    }} else {{
                        startNoise(type);
                    }}
                }}

                function stopNoise(
                    update = true
                ) {{
                    if (sourceNode) {{
                        try {{
                            sourceNode.stop();
                        }} catch (error) {{
                            // Source may already be stopped.
                        }}
                        sourceNode.disconnect();
                        sourceNode = null;
                    }}

                    if (gainNode) {{
                        gainNode.disconnect();
                        gainNode = null;
                    }}

                    currentType = null;

                    if (update) {{
                        updateButtons();
                    }}
                }}

                function updateVolume(value) {{
                    if (gainNode) {{
                        gainNode.gain.value =
                            Number(value);
                    }}
                }}
            </script>
        </body>
        </html>
        """,
        height=220,
        scrolling=False,
    )


def render_global_focus_sound_controls() -> None:
    white_col, brown_col, stop_col = (
        st.columns(3)
    )

    with white_col:
        if st.button(
            "White noise",
            key="global_white_noise",
            use_container_width=True,
        ):
            activate_persistent_music(
                generate_focus_noise_data_url(
                    "white"
                ),
                "White noise",
                loop=True,
                force_reload=True,
            )
            st.rerun()

    with brown_col:
        if st.button(
            "Brown noise",
            key="global_brown_noise",
            use_container_width=True,
        ):
            activate_persistent_music(
                generate_focus_noise_data_url(
                    "brown"
                ),
                "Brown noise",
                loop=True,
                force_reload=True,
            )
            st.rerun()

    with stop_col:
        if st.button(
            "Stop sound",
            key="stop_global_focus_sound",
            use_container_width=True,
            disabled=not st.session_state[
                "persistent_music_active"
            ],
        ):
            stop_persistent_music()
            st.rerun()

def search_focus_music(
    query: str,
    api_key: str,
    page_token: str = "",
    max_results: int = 12,
) -> tuple[list[dict], str, int]:
    clean_query = query.strip()

    if not clean_query:
        raise RuntimeError(
            "Enter a song, artist, album, or study-music topic."
        )

    music_terms = {
        "music",
        "song",
        "songs",
        "audio",
        "playlist",
        "lofi",
        "instrumental",
        "soundtrack",
    }
    query_words = {
        word.strip(".,!?").lower()
        for word in clean_query.split()
    }

    search_query = (
        clean_query
        if query_words & music_terms
        else f"{clean_query} music"
    )

    (
        videos,
        next_page_token,
        total_results,
        _,
    ) = search_youtube_watcher(
        search_query,
        api_key,
        "Topic",
        "Relevant",
        "Videos",
        page_token=page_token,
        max_results=max_results,
    )

    return (
        unique_youtube_videos(videos),
        next_page_token,
        total_results,
    )


def render_focus_music_search_player(
    videos: list[dict],
) -> None:
    if not videos:
        return

    selected_index = max(
        0,
        min(
            int(
                st.session_state[
                    "music_selected_index"
                ]
            ),
            len(videos) - 1,
        ),
    )
    st.session_state.music_selected_index = (
        selected_index
    )
    selected_video = videos[
        selected_index
    ]

    auto_activate_persistent_music(
        selected_video["url"],
        selected_video["title"],
    )

    st.markdown(
        f"""
        <div class="music-player-shell">
            <div class="
                youtube-player-title">
                {html.escape(
                    selected_video["title"]
                )}
            </div>
            <div class="
                youtube-player-meta">
                {html.escape(
                    selected_video["channel"]
                )} ·
                {format_youtube_date(
                    selected_video[
                        "published_at"
                    ]
                )} ·
                {selected_video.get(
                    "duration_text",
                    "Duration unavailable",
                )}
            </div>
        </div>
        """,
        unsafe_allow_html=True,
    )

    st.video(
        selected_video["url"]
    )

    save_col, open_col = st.columns(2)

    with save_col:
        render_save_media_button(
            selected_video,
            key=(
                "save_current_music_"
                f"{selected_video['video_id']}"
            ),
            category="Music",
            label="♡ Save music",
        )

    with open_col:
        st.link_button(
            "Open on YouTube ↗",
            selected_video["url"],
            use_container_width=True,
        )

    previous_col, counter_col, next_col = (
        st.columns(
            [1, 1.25, 1]
        )
    )

    with previous_col:
        if st.button(
            "← Previous",
            key="music_previous_result",
            use_container_width=True,
            disabled=len(videos) <= 1,
        ):
            st.session_state.music_selected_index = (
                selected_index - 1
            ) % len(videos)
            st.rerun()

    with counter_col:
        st.markdown(
            f"""
            <div style="
                text-align:center;
                color:var(--text-soft);
                padding:0.72rem 0;
                font-weight:700;">
                Result {selected_index + 1}
                of {len(videos)}
            </div>
            """,
            unsafe_allow_html=True,
        )

    with next_col:
        if st.button(
            "Next →",
            key="music_next_result",
            use_container_width=True,
            disabled=len(videos) <= 1,
        ):
            st.session_state.music_selected_index = (
                selected_index + 1
            ) % len(videos)
            st.rerun()






def render_focus_music_suggestions(
    videos: list[dict],
) -> None:
    if not videos:
        return

    st.markdown(
        "### Music suggestions"
    )

    for row_start in range(
        0,
        len(videos),
        3,
    ):
        columns = st.columns(3)
        row_videos = videos[
            row_start:
            row_start + 3
        ]

        for offset, (
            column,
            video,
        ) in enumerate(
            zip(
                columns,
                row_videos,
            )
        ):
            result_index = (
                row_start + offset
            )

            with column:
                with st.container(
                    border=True
                ):
                    if video.get(
                        "thumbnail"
                    ):
                        st.image(
                            video["thumbnail"],
                            use_container_width=True,
                        )

                    st.markdown(
                        f"""
                        <div class="
                            youtube-result-title">
                            {html.escape(
                                shorten_text(
                                    video["title"],
                                    84,
                                )
                            )}
                        </div>
                        <div class="
                            youtube-result-meta">
                            {html.escape(
                                video["channel"]
                            )}<br>
                            {format_youtube_date(
                                video[
                                    "published_at"
                                ]
                            )}
                            · {video.get(
                                "duration_text",
                                "Duration unavailable",
                            )}
                        </div>
                        """,
                        unsafe_allow_html=True,
                    )

                    (
                        play_col,
                        save_col,
                        open_col,
                    ) = st.columns(3)

                    with play_col:
                        if st.button(
                            "▶ Play",
                            key=(
                                "music_play_result_"
                                f"{video['video_id']}_"
                                f"{result_index}"
                            ),
                            use_container_width=True,
                        ):
                            st.session_state[
                                "music_selected_index"
                            ] = result_index
                            st.rerun()

                    with save_col:
                        render_save_media_button(
                            video,
                            key=(
                                "music_save_result_"
                                f"{video['video_id']}_"
                                f"{result_index}"
                            ),
                            category="Music",
                        )

                    with open_col:
                        st.link_button(
                            "Open ↗",
                            video["url"],
                            use_container_width=True,
                        )


def focus_music_page() -> None:
    initialize_music_state()

    st.subheader("Focus Music")
    st.caption(
        "Search music, paste a link, upload audio, "
        "or use browser focus sounds."
    )

    st.markdown(
        """
        <div class="music-hero">
            <div class="music-hero-row">
                <div class="music-mark">♫</div>
                <div>
                    <div class="music-title">
                        Music for focused study
                    </div>
                    <div class="music-subtitle">
                        One general option controls every
                        music source in StudyDragon.
                    </div>
                </div>
            </div>
        </div>
        """,
        unsafe_allow_html=True,
    )

    persistence_choice = st.toggle(
        "Keep music playing across pages",
        value=bool(
            st.session_state[
                "music_persistence_enabled"
            ]
        ),
        key="all_music_persistence_choice",
        help=(
            "When enabled, all music sources use the floating player."
        ),
    )

    if (
        persistence_choice
        != st.session_state[
            "music_persistence_enabled"
        ]
    ):
        st.session_state[
            "music_persistence_enabled"
        ] = persistence_choice

        if persistence_choice:
            if st.session_state[
                "persistent_music_url"
            ]:
                activate_persistent_music(
                    st.session_state[
                        "persistent_music_url"
                    ],
                    st.session_state[
                        "persistent_music_title"
                    ],
                    loop=bool(
                        st.session_state[
                            "persistent_music_loop"
                        ]
                    ),
                    force_reload=True,
                )
        else:
            if not st.session_state.get(
                "youtube_persistence_enabled",
                False,
            ):
                stop_persistent_music()
                st.session_state.persistent_music_active = False

        st.rerun()

    youtube_api_key = (
        get_default_youtube_api_key()
    )

    with st.form(
        "focus_music_search_form",
        clear_on_submit=False,
        border=True,
    ):
        search_query = st.text_input(
            "Search music",
            value=(
                st.session_state[
                    "music_search_query"
                ]
            ),
            placeholder=(
                "Search a song, artist, album, "
                "lo-fi mix, soundtrack, or playlist..."
            ),
            label_visibility="collapsed",
        )

        search_col, clear_col = (
            st.columns([2, 1])
        )

        with search_col:
            search_clicked = (
                st.form_submit_button(
                    "🔍 Search music",
                    type="primary",
                    use_container_width=True,
                )
            )

        with clear_col:
            clear_search_clicked = (
                st.form_submit_button(
                    "Clear results",
                    use_container_width=True,
                )
            )

    if clear_search_clicked:
        st.session_state.music_search_query = ""
        st.session_state.music_search_results = []
        st.session_state.music_search_next_token = ""
        st.session_state.music_search_total = 0
        st.session_state.music_search_error = ""
        st.session_state.music_selected_index = 0
        st.rerun()

    if search_clicked:
        if not youtube_api_key:
            st.session_state.music_search_error = (
                "YOUTUBE_API_KEY is not configured."
            )
        elif not search_query.strip():
            st.session_state.music_search_error = (
                "Enter a song, artist, album, "
                "or study-music topic."
            )
        else:
            try:
                with st.spinner(
                    "Searching for music..."
                ):
                    (
                        music_results,
                        next_page_token,
                        total_results,
                    ) = search_focus_music(
                        search_query,
                        youtube_api_key,
                        max_results=12,
                    )

                st.session_state.music_search_query = (
                    search_query.strip()
                )
                st.session_state.music_search_results = (
                    music_results
                )
                st.session_state.music_search_next_token = (
                    next_page_token
                )
                st.session_state.music_search_total = (
                    total_results
                )
                st.session_state.music_selected_index = 0
                st.session_state.music_search_error = ""

                if not music_results:
                    st.session_state.music_search_error = (
                        "No matching music results "
                        "were found."
                    )

            except RuntimeError as error:
                st.session_state.music_search_results = []
                st.session_state.music_search_next_token = ""
                st.session_state.music_search_error = (
                    str(error)
                )

    if st.session_state.music_search_error:
        st.error(
            st.session_state.music_search_error
        )

    music_results = (
        st.session_state.music_search_results
    )

    if music_results:
        st.markdown("### Now playing")
        render_focus_music_search_player(
            music_results
        )

        st.caption(
            f"Showing {len(music_results)} result(s)"
            + (
                " from approximately "
                f"{st.session_state.music_search_total:,} "
                "matches."
                if st.session_state.music_search_total
                else "."
            )
        )

        render_focus_music_suggestions(
            music_results
        )

        next_page_token = (
            st.session_state.music_search_next_token
        )

        if next_page_token:
            _, more_col, _ = st.columns(
                [1.5, 1, 1.5]
            )

            with more_col:
                if st.button(
                    "Show more music",
                    type="primary",
                    use_container_width=True,
                ):
                    try:
                        with st.spinner(
                            "Loading more music..."
                        ):
                            (
                                more_results,
                                new_next_token,
                                total_results,
                            ) = search_focus_music(
                                st.session_state[
                                    "music_search_query"
                                ],
                                youtube_api_key,
                                page_token=(
                                    next_page_token
                                ),
                                max_results=12,
                            )

                        st.session_state[
                            "music_search_results"
                        ] = unique_youtube_videos(
                            music_results
                            + more_results
                        )
                        st.session_state[
                            "music_search_next_token"
                        ] = new_next_token
                        st.session_state[
                            "music_search_total"
                        ] = total_results
                        st.rerun()

                    except RuntimeError as error:
                        st.error(str(error))

    with st.expander(
        "Paste a Spotify, YouTube, "
        "or direct-audio link",
        expanded=not bool(music_results),
    ):
        with st.form(
            "focus_music_url_form",
            clear_on_submit=False,
            border=False,
        ):
            music_url = st.text_input(
                "Music link",
                value=(
                    st.session_state[
                        "music_embed_url"
                    ]
                ),
                placeholder=(
                    "Paste a Spotify or YouTube "
                    "link, playlist, or direct MP3 URL..."
                ),
            )

            load_col, clear_col = (
                st.columns(2)
            )

            with load_col:
                load_clicked = (
                    st.form_submit_button(
                        "▶ Load link",
                        type="primary",
                        use_container_width=True,
                    )
                )

            with clear_col:
                clear_clicked = (
                    st.form_submit_button(
                        "Clear player",
                        use_container_width=True,
                    )
                )

        if clear_clicked:
            st.session_state.music_embed_url = ""
            st.session_state.music_embed_error = ""
            st.rerun()

        if load_clicked:
            normalized_url = normalize_music_url(
                music_url
            )

            if not normalized_url:
                st.session_state.music_embed_error = (
                    "Paste a music link first."
                )
            elif (
                spotify_embed_details(
                    normalized_url
                )
                or youtube_embed_details(
                    normalized_url
                )
                or direct_audio_url(
                    normalized_url
                )
            ):
                st.session_state.music_embed_url = (
                    normalized_url
                )
                st.session_state.music_embed_error = ""

                auto_activate_persistent_music(
                    normalized_url,
                    "Pasted music link",
                )
            else:
                st.session_state.music_embed_error = (
                    "That link is not recognized. "
                    "Use Spotify, YouTube, a playlist, "
                    "or a direct audio-file URL."
                )

        if st.session_state.music_embed_error:
            st.error(
                st.session_state.music_embed_error
            )

        if st.session_state.music_embed_url:
            st.markdown(
                "#### Embedded link player"
            )

            with st.container(border=True):
                rendered = render_music_from_url(
                    st.session_state[
                        "music_embed_url"
                    ]
                )

                if not rendered:
                    st.error(
                        "The player could not be "
                        "loaded from this link."
                    )

            saved_link_url = st.session_state[
                "music_embed_url"
            ]
            pasted_saved = is_study_resource_saved(
                saved_link_url
            )

            if st.button(
                (
                    "✓ Link saved"
                    if pasted_saved
                    else "♡ Save this music link"
                ),
                key="save_pasted_music_link",
                use_container_width=True,
                disabled=pasted_saved,
            ):
                success, message = add_study_resource(
                    "Saved music link",
                    saved_link_url,
                    "Music",
                    "Saved from Focus Music.",
                )

                st.toast(
                    message,
                    icon=(
                        "✅"
                        if success
                        else "ℹ️"
                    ),
                )

                if success:
                    st.rerun()

    st.divider()

    upload_col, sounds_col = (
        st.columns([1, 1])
    )

    with upload_col:
        st.markdown(
            "### Upload your own audio"
        )

        uploaded_audio = st.file_uploader(
            "Choose an audio file",
            type=[
                "mp3",
                "wav",
                "ogg",
                "m4a",
                "aac",
                "flac",
            ],
            help=(
                "Files up to 25 MB can use "
                "the persistent floating player."
            ),
        )

        if uploaded_audio:
            st.audio(uploaded_audio)

            try:
                (
                    audio_name,
                    audio_data_url,
                    audio_signature,
                ) = uploaded_audio_to_data_url(
                    uploaded_audio
                )

                if (
                    st.session_state[
                        "uploaded_music_signature"
                    ]
                    != audio_signature
                ):
                    st.session_state[
                        "uploaded_music_signature"
                    ] = audio_signature

                    auto_activate_persistent_music(
                        audio_data_url,
                        audio_name,
                    )

            except ValueError as error:
                st.warning(str(error))

    with sounds_col:
        st.markdown("### Focus sounds")

        if st.session_state[
            "music_persistence_enabled"
        ]:
            render_global_focus_sound_controls()
        else:
            render_focus_sound_generator(
                st.session_state.app_theme
            )






def additional_resources_page() -> None:
    st.subheader("Additional Resources")
    st.caption(
        "Search videos, play focus music, save useful links, "
        "and open trusted study tools."
    )

    (
        youtube_tab,
        music_tab,
        saved_tab,
        tools_tab,
    ) = st.tabs(
        [
            "▶ YouTube Watcher",
            "🎵 Focus Music",
            "💾 Saved Media & Resources",
            "🧰 Study Tools",
        ]
    )

    with youtube_tab:
        youtube_api_key = get_default_youtube_api_key()

        st.markdown(
            """
            <div class="youtube-shell">
                <div class="youtube-brand-row">
                    <div class="youtube-play-mark">▶</div>
                    <div>
                        <div class="youtube-watcher-title">
                            YouTube Watcher
                        </div>
                        <div class="youtube-watcher-subtitle">
                            Search a topic or channel, watch a result,
                            and move through related suggestions.
                        </div>
                    </div>
                </div>
            </div>
            """,
            unsafe_allow_html=True,
        )

        youtube_persistence_choice = st.toggle(
            "Keep YouTube playing across pages",
            value=bool(
                st.session_state.youtube_persistence_enabled
            ),
            key="youtube_persistence_choice",
            help=(
                "The selected video or Short will use the same "
                "floating player while you navigate StudyDragon."
            ),
        )

        if (
            youtube_persistence_choice
            != st.session_state.youtube_persistence_enabled
        ):
            st.session_state.youtube_persistence_enabled = (
                youtube_persistence_choice
            )

            current_youtube_video = st.session_state.get(
                "youtube_watcher_selected"
            )

            if (
                youtube_persistence_choice
                and current_youtube_video
            ):
                activate_persistent_music(
                    current_youtube_video["url"],
                    current_youtube_video["title"],
                    force_reload=True,
                )
            elif not st.session_state.music_persistence_enabled:
                stop_persistent_music()

            st.rerun()

        with st.container(border=True):
            with st.form(
                "youtube_watcher_search_form",
                clear_on_submit=False,
                border=False,
            ):
                search_query = st.text_input(
                    "Search YouTube",
                    value=st.session_state.get(
                        "youtube_watcher_query",
                        "",
                    ),
                    placeholder=(
                        "Search a topic, lesson, creator, "
                        "or @channel..."
                    ),
                    label_visibility="collapsed",
                )

                st.markdown(
                    '<div class="youtube-search-help">'
                    'Examples: “calculus limits,” '
                    '“Python recursion,” “Khan Academy,” '
                    'or “@3blue1brown”'
                    "</div>",
                    unsafe_allow_html=True,
                )

                (
                    mode_col,
                    type_col,
                    order_col,
                    button_col,
                ) = st.columns(
                    [1.15, 1.15, 1.15, 0.85]
                )

                with mode_col:
                    search_mode = st.radio(
                        "Search for",
                        ["Topic", "Channel"],
                        horizontal=True,
                        index=(
                            1
                            if st.session_state.get(
                                "youtube_watcher_mode"
                            ) == "Channel"
                            else 0
                        ),
                    )

                with type_col:
                    video_type_options = [
                        "Everything",
                        "Videos",
                        "Shorts",
                    ]
                    saved_video_type = (
                        st.session_state.get(
                            "youtube_watcher_video_type",
                            "Everything",
                        )
                    )
                    video_type = st.selectbox(
                        "Type",
                        video_type_options,
                        index=video_type_options.index(
                            saved_video_type
                            if saved_video_type
                            in video_type_options
                            else "Everything"
                        ),
                    )

                with order_col:
                    order_options = [
                        "Relevant",
                        "Newest",
                        "Most viewed",
                    ]
                    saved_order = st.session_state.get(
                        "youtube_watcher_order",
                        "Relevant",
                    )
                    sort_order = st.selectbox(
                        "Sort",
                        order_options,
                        index=order_options.index(
                            saved_order
                            if saved_order in order_options
                            else "Relevant"
                        ),
                    )

                with button_col:
                    st.write("")
                    search_submitted = (
                        st.form_submit_button(
                            "🔍 Search",
                            type="primary",
                            use_container_width=True,
                        )
                    )

        if search_submitted:
            if not youtube_api_key:
                st.error(
                    "YouTube Watcher is not connected yet."
                )
            elif not search_query.strip():
                st.warning(
                    "Enter a topic or channel before searching."
                )
            else:
                try:
                    with st.spinner(
                        "Searching YouTube..."
                    ):
                        (
                            videos,
                            next_page_token,
                            total_results,
                            resolved_label,
                        ) = search_youtube_watcher(
                            search_query,
                            youtube_api_key,
                            search_mode,
                            sort_order,
                            video_type,
                            max_results=12,
                        )

                        extra_shorts: list[dict] = []
                        extra_shorts_next_token = ""

                        if video_type == "Everything":
                            (
                                extra_shorts,
                                extra_shorts_next_token,
                                _,
                                _,
                            ) = search_youtube_watcher(
                                search_query,
                                youtube_api_key,
                                search_mode,
                                sort_order,
                                "Shorts",
                                max_results=6,
                            )

                            main_ids = {
                                video["video_id"]
                                for video in videos
                            }
                            extra_shorts = [
                                video
                                for video in extra_shorts
                                if video["video_id"]
                                not in main_ids
                            ][:4]

                    videos = unique_youtube_videos(videos)
                    extra_shorts = unique_youtube_videos(
                        extra_shorts
                    )

                    st.session_state.youtube_watcher_query = (
                        search_query.strip()
                    )
                    st.session_state.youtube_watcher_mode = (
                        search_mode
                    )
                    st.session_state.youtube_watcher_order = (
                        sort_order
                    )
                    st.session_state.youtube_watcher_video_type = (
                        video_type
                    )
                    st.session_state.youtube_watcher_results = (
                        videos
                    )
                    st.session_state.youtube_watcher_next_token = (
                        next_page_token
                    )
                    st.session_state.youtube_watcher_total = (
                        total_results
                    )
                    st.session_state.youtube_watcher_label = (
                        resolved_label
                    )
                    st.session_state.youtube_watcher_extra_shorts = (
                        extra_shorts
                    )
                    st.session_state.youtube_watcher_extra_shorts_next = (
                        extra_shorts_next_token
                    )

                    first_video = (
                        videos[0]
                        if videos
                        else (
                            extra_shorts[0]
                            if extra_shorts
                            else None
                        )
                    )

                    if first_video:
                        first_source = (
                            "main_shorts"
                            if first_video.get(
                                "video_type"
                            ) == "Short"
                            else "main"
                        )

                        if (
                            not videos
                            and extra_shorts
                        ):
                            first_source = "extra_shorts"

                        set_youtube_watcher_selection(
                            first_video,
                            first_source,
                        )
                    else:
                        st.session_state.youtube_watcher_selected = (
                            None
                        )
                        st.session_state.youtube_watcher_selected_source = (
                            "main"
                        )

                    st.session_state.youtube_watcher_error = ""

                except RuntimeError as error:
                    st.session_state.youtube_watcher_results = []
                    st.session_state.youtube_watcher_extra_shorts = []
                    st.session_state.youtube_watcher_next_token = ""
                    st.session_state.youtube_watcher_error = (
                        str(error)
                    )

        watcher_error = st.session_state.get(
            "youtube_watcher_error",
            "",
        )

        if watcher_error:
            st.error(watcher_error)

        videos = st.session_state.get(
            "youtube_watcher_results",
            [],
        )
        extra_shorts = st.session_state.get(
            "youtube_watcher_extra_shorts",
            [],
        )
        selected_video = st.session_state.get(
            "youtube_watcher_selected"
        )
        selected_source = st.session_state.get(
            "youtube_watcher_selected_source",
            "main",
        )
        selected_video_type = st.session_state.get(
            "youtube_watcher_video_type",
            "Everything",
        )

        if (
            selected_video
            and st.session_state.youtube_persistence_enabled
        ):
            activate_persistent_music(
                selected_video["url"],
                selected_video["title"],
            )

        main_short_results = [
            video
            for video in videos
            if video.get("video_type") == "Short"
        ]
        main_video_results = [
            video
            for video in videos
            if video.get("video_type") != "Short"
        ]

        playlists = {
            "main": (
                main_video_results
                if main_video_results
                else videos
            ),
            "main_shorts": main_short_results,
            "extra_shorts": extra_shorts,
        }

        selected_playlist = playlists.get(
            selected_source,
            videos,
        )

        if (
            selected_video
            and selected_video.get("video_type")
            == "Short"
        ):
            short_playlist = (
                selected_playlist
                if selected_playlist
                else [selected_video]
            )
            start_index = find_video_index(
                short_playlist,
                selected_video,
            )

            st.markdown("### Now watching")
            render_shorts_scroll_feed(
                short_playlist,
                st.session_state.app_theme,
                start_index=start_index,
            )

            short_save_col, short_open_col = st.columns(2)

            with short_save_col:
                render_save_media_button(
                    selected_video,
                    key=(
                        "save_selected_short_"
                        f"{selected_video['video_id']}"
                    ),
                    category="Short",
                    label="♡ Save Short",
                )

            with short_open_col:
                st.link_button(
                    "Open on YouTube ↗",
                    selected_video["url"],
                    use_container_width=True,
                )

            short_previous_col, short_counter_col, short_next_col = (
                st.columns([1, 1.4, 1])
            )

            with short_previous_col:
                if st.button(
                    "← Previous Short",
                    key=(
                        "youtube_previous_short_"
                        f"{selected_video['video_id']}"
                    ),
                    use_container_width=True,
                    disabled=len(short_playlist) <= 1,
                ):
                    previous_short = short_playlist[
                        (start_index - 1)
                        % len(short_playlist)
                    ]
                    set_youtube_watcher_selection(
                        previous_short,
                        selected_source,
                    )
                    st.rerun()

            with short_counter_col:
                st.markdown(
                    f"""
                    <div style="
                        text-align:center;
                        color:var(--text-soft);
                        padding:0.72rem 0;
                        font-weight:700;">
                        Short {start_index + 1}
                        of {len(short_playlist)}
                    </div>
                    """,
                    unsafe_allow_html=True,
                )

            with short_next_col:
                if st.button(
                    "Next Short →",
                    key=(
                        "youtube_next_short_"
                        f"{selected_video['video_id']}"
                    ),
                    use_container_width=True,
                    disabled=len(short_playlist) <= 1,
                ):
                    next_short = short_playlist[
                        (start_index + 1)
                        % len(short_playlist)
                    ]
                    set_youtube_watcher_selection(
                        next_short,
                        selected_source,
                    )
                    st.rerun()

        elif selected_video:
            standard_playlist = (
                selected_playlist
                if selected_playlist
                else [selected_video]
            )
            st.markdown("### Now watching")
            render_standard_youtube_player(
                selected_video,
                standard_playlist,
                selected_source,
            )

        if videos or extra_shorts:
            result_label = html.escape(
                str(
                    st.session_state.get(
                        "youtube_watcher_label",
                        st.session_state.get(
                            "youtube_watcher_query",
                            "",
                        ),
                    )
                )
            )

            if selected_video_type == "Shorts":
                st.markdown(
                    f"### More Shorts for “{result_label}”"
                )
                st.caption(
                    "Click a suggestion below, or scroll and "
                    "use the arrow buttons in the Shorts viewer."
                )
                render_youtube_short_suggestions(
                    main_short_results,
                    "main_short_suggestions",
                    "main_shorts",
                )

            elif selected_video_type == "Videos":
                st.markdown(
                    f"### Suggested videos for “{result_label}”"
                )
                render_youtube_video_grid(
                    main_video_results,
                    "video_suggestions",
                    "main",
                    "main_shorts",
                )

            else:
                st.markdown(
                    f"### Top results for “{result_label}”"
                )
                render_youtube_video_grid(
                    videos,
                    "everything_suggestions",
                    "main",
                    "main_shorts",
                )

                st.divider()
                st.markdown(
                    f"### Shorts for “{result_label}”"
                )
                st.caption(
                    "A few shorter results are included "
                    "separately so they are easier to find."
                )

                shorts_for_everything = (
                    extra_shorts
                    if extra_shorts
                    else main_short_results[:4]
                )
                render_youtube_short_suggestions(
                    shorts_for_everything,
                    "everything_short_suggestions",
                    (
                        "extra_shorts"
                        if extra_shorts
                        else "main_shorts"
                    ),
                )

            main_next_token = st.session_state.get(
                "youtube_watcher_next_token",
                "",
            )

            if main_next_token:
                left_space, more_col, right_space = (
                    st.columns([1.5, 1, 1.5])
                )

                with more_col:
                    more_label = (
                        "Show more Shorts"
                        if selected_video_type == "Shorts"
                        else (
                            "Show more videos"
                            if selected_video_type == "Videos"
                            else "Show more results"
                        )
                    )

                    if st.button(
                        more_label,
                        type="primary",
                        key="youtube_more_main",
                        use_container_width=True,
                    ):
                        try:
                            with st.spinner(
                                "Loading more results..."
                            ):
                                (
                                    more_videos,
                                    new_next_token,
                                    total_results,
                                    _,
                                ) = search_youtube_watcher(
                                    st.session_state[
                                        "youtube_watcher_query"
                                    ],
                                    youtube_api_key,
                                    st.session_state[
                                        "youtube_watcher_mode"
                                    ],
                                    st.session_state[
                                        "youtube_watcher_order"
                                    ],
                                    selected_video_type,
                                    page_token=main_next_token,
                                    max_results=12,
                                )

                            st.session_state.youtube_watcher_results = (
                                unique_youtube_videos(
                                    videos + more_videos
                                )
                            )
                            st.session_state.youtube_watcher_next_token = (
                                new_next_token
                            )
                            st.session_state.youtube_watcher_total = (
                                total_results
                            )
                            st.rerun()

                        except RuntimeError as error:
                            st.error(str(error))

            extra_short_token = st.session_state.get(
                "youtube_watcher_extra_shorts_next",
                "",
            )

            if (
                selected_video_type == "Everything"
                and extra_short_token
            ):
                left_space, shorts_more_col, right_space = (
                    st.columns([1.5, 1, 1.5])
                )

                with shorts_more_col:
                    if st.button(
                        "Show more Shorts",
                        key="youtube_more_extra_shorts",
                        use_container_width=True,
                    ):
                        try:
                            with st.spinner(
                                "Loading more Shorts..."
                            ):
                                (
                                    more_shorts,
                                    new_short_token,
                                    _,
                                    _,
                                ) = search_youtube_watcher(
                                    st.session_state[
                                        "youtube_watcher_query"
                                    ],
                                    youtube_api_key,
                                    st.session_state[
                                        "youtube_watcher_mode"
                                    ],
                                    st.session_state[
                                        "youtube_watcher_order"
                                    ],
                                    "Shorts",
                                    page_token=extra_short_token,
                                    max_results=6,
                                )

                            existing_main_ids = {
                                video["video_id"]
                                for video in videos
                            }
                            more_shorts = [
                                video
                                for video in more_shorts
                                if video["video_id"]
                                not in existing_main_ids
                            ]

                            st.session_state.youtube_watcher_extra_shorts = (
                                unique_youtube_videos(
                                    extra_shorts
                                    + more_shorts
                                )
                            )
                            st.session_state.youtube_watcher_extra_shorts_next = (
                                new_short_token
                            )
                            st.rerun()

                        except RuntimeError as error:
                            st.error(str(error))

        else:
            st.markdown(
                """
                <div class="youtube-empty">
                    <strong>
                        Search for something to watch.
                    </strong><br>
                    Find lessons, tutorials, creators,
                    videos, or Shorts.
                </div>
                """,
                unsafe_allow_html=True,
            )

    with music_tab:
        focus_music_page()

    with saved_tab:
        st.markdown(
            '<div class="section-eyebrow">Personal library</div>',
            unsafe_allow_html=True,
        )
        st.markdown("### Saved media and study resources")

        with st.form(
            "add_study_resource_form",
            clear_on_submit=True,
        ):
            resource_left, resource_right = st.columns(2)

            with resource_left:
                resource_title = st.text_input(
                    "Resource title",
                    placeholder="Example: Algebra practice problems",
                )
                resource_url = st.text_input(
                    "Resource URL",
                    placeholder="https://...",
                )

            with resource_right:
                resource_category = st.selectbox(
                    "Category",
                    [
                        "Music",
                        "Video",
                        "Short",
                        "Website",
                        "Article",
                        "Practice",
                        "Reference",
                        "Other",
                    ],
                )
                resource_notes = st.text_area(
                    "Notes",
                    placeholder="Why this resource is useful...",
                    height=96,
                )

            save_resource_button = st.form_submit_button(
                "Save resource",
                type="primary",
                use_container_width=True,
            )

        if save_resource_button:
            if (
                not resource_title.strip()
                or not resource_url.strip()
            ):
                st.error("Enter both a title and URL.")
            else:
                success, message = add_study_resource(
                    resource_title,
                    resource_url,
                    resource_category,
                    resource_notes,
                )

                if success:
                    st.success(message)
                    st.rerun()
                else:
                    st.error(message)

        resources = get_study_resources()

        if not resources:
            st.info("Your saved resource library is empty.")
        else:
            category_options = ["All categories"] + sorted(
                {
                    resource["category"]
                    for resource in resources
                }
            )

            resource_category_filter = st.selectbox(
                "Filter resources",
                category_options,
            )

            filtered_resources = resources

            if resource_category_filter != "All categories":
                filtered_resources = [
                    resource
                    for resource in resources
                    if resource["category"]
                    == resource_category_filter
                ]

            for resource in filtered_resources:
                safe_title = html.escape(resource["title"])
                safe_category = html.escape(
                    resource["category"]
                )
                safe_notes = html.escape(
                    resource["notes"]
                    or "No notes were added."
                )

                st.markdown(
                    f"""
                    <div class="resource-card">
                        <h4>{safe_title}</h4>
                        <span class="badge teal">{safe_category}</span>
                        <div class="resource-description"
                             style="margin-top:0.55rem;">
                            {safe_notes}
                        </div>
                    </div>
                    """,
                    unsafe_allow_html=True,
                )

                open_col, delete_col = st.columns([3, 1])

                with open_col:
                    st.link_button(
                        "Open resource",
                        resource["resource_url"],
                        use_container_width=True,
                    )

                with delete_col:
                    if st.button(
                        "Delete",
                        key=f"delete_resource_{resource['id']}",
                        use_container_width=True,
                    ):
                        delete_study_resource(resource["id"])
                        st.success("Resource deleted.")
                        st.rerun()

    with tools_tab:
        st.markdown(
            '<div class="section-eyebrow">Quick access</div>',
            unsafe_allow_html=True,
        )
        st.markdown("### Useful study tools")

        study_tools = [
            {
                "name": "Khan Academy",
                "description": (
                    "Lessons and practice across mathematics, "
                    "science, computing, economics, and more."
                ),
                "url": "https://www.khanacademy.org/",
            },
            {
                "name": "Desmos",
                "description": (
                    "Graphing calculator and interactive "
                    "mathematics tools."
                ),
                "url": "https://www.desmos.com/calculator",
            },
            {
                "name": "WolframAlpha",
                "description": (
                    "Computational answers, formulas, graphs, "
                    "and step-based mathematical exploration."
                ),
                "url": "https://www.wolframalpha.com/",
            },
            {
                "name": "Quizlet",
                "description": (
                    "Flashcards and study sets for vocabulary, "
                    "definitions, and review."
                ),
                "url": "https://quizlet.com/",
            },
            {
                "name": "Google Scholar",
                "description": (
                    "Search scholarly articles, books, papers, "
                    "and academic sources."
                ),
                "url": "https://scholar.google.com/",
            },
            {
                "name": "Project Gutenberg",
                "description": (
                    "A large collection of free public-domain "
                    "ebooks and classic literature."
                ),
                "url": "https://www.gutenberg.org/",
            },
        ]

        for index in range(0, len(study_tools), 2):
            columns = st.columns(2)

            for column, tool in zip(
                columns,
                study_tools[index:index + 2],
            ):
                with column:
                    st.markdown(
                        f"""
                        <div class="tool-card">
                            <h4>{html.escape(tool["name"])}</h4>
                            <div class="tool-description">
                                {html.escape(tool["description"])}
                            </div>
                        </div>
                        """,
                        unsafe_allow_html=True,
                    )
                    st.link_button(
                        f"Open {tool['name']}",
                        tool["url"],
                        use_container_width=True,
                    )





# ---------------------------------------------------------
# MAIN APP
# ---------------------------------------------------------

initialize_database()
initialize_timer_state()
initialize_music_state()

tasks = get_tasks()
availability = get_availability()

with st.sidebar:
    st.markdown(
        f"""
        <div class="brand">
            <div class="brand-row">
                <img
                    class="brand-logo"
                    src="{LOGO_DATA_URI}"
                    alt="Half-cut dragonfruit logo"
                >
                <div class="brand-copy">
                    <div class="brand-title">{APP_NAME}</div>
                    <div class="brand-subtitle">
                        {APP_TAGLINE}
                    </div>
                </div>
            </div>
        </div>
        """,
        unsafe_allow_html=True,
    )

    st.markdown(
        '<div class="theme-label">Appearance</div>',
        unsafe_allow_html=True,
    )

    dark_mode_enabled = st.toggle(
        "🌙 Dark mode",
        value=st.session_state.app_theme == "Dark",
        help="Turn this off to use the light theme.",
    )

    requested_theme = "Dark" if dark_mode_enabled else "Light"

    if requested_theme != st.session_state.app_theme:
        st.session_state.app_theme = requested_theme
        st.rerun()

    st.markdown(
        '<div class="theme-label">Dragonfruit theme</div>',
        unsafe_allow_html=True,
    )

    fruit_columns = st.columns(3)

    fruit_options = [
        (
            "yellow_white",
            "Yellow / White",
        ),
        (
            "red_white",
            "Red / White",
        ),
        (
            "red_red",
            "Red / Red",
        ),
    ]

    for column, (
        flavor_key,
        short_label,
    ) in zip(
        fruit_columns,
        fruit_options,
    ):
        with column:
            st.image(
                THEME_FRUIT_BYTES[
                    flavor_key
                ],
                use_container_width=True,
            )

            is_selected = (
                st.session_state.theme_flavor
                == flavor_key
            )

            if st.button(
                "Selected" if is_selected else short_label,
                key=f"fruit_theme_{flavor_key}",
                use_container_width=True,
                disabled=is_selected,
            ):
                st.session_state.theme_flavor = flavor_key
                st.rerun()

    st.caption(
        "Pick a dragonfruit to change the site's color theme."
    )

    st.divider()

    page = st.radio(
        "Navigation",
        [
            "🏠 Dashboard",
            "➕ Add Task",
            "✅ My Tasks",
            "⏱️ Focus Timer",
            "🗓️ Study Plan",
            "📚 Additional Resources",
        ],
        label_visibility="collapsed",
    )

    st.divider()

    active_count = len([
        task for task in tasks if not task["completed"]
    ])

    urgent_count = len([
        task
        for task in tasks
        if not task["completed"] and days_remaining(task) <= 1
    ])

    today_minutes, _ = get_today_focus_stats()

    st.metric("Active tasks", active_count)
    st.metric("Urgent / overdue", urgent_count)
    st.metric("Focused today", f"{today_minutes} min")

render_header()

if page == "🏠 Dashboard":
    dashboard_page(tasks, availability)
elif page == "➕ Add Task":
    add_task_page()
elif page == "✅ My Tasks":
    my_tasks_page(tasks)
elif page == "⏱️ Focus Timer":
    focus_timer_page(tasks)
elif page == "🗓️ Study Plan":
    study_plan_page(tasks, availability)
else:
    additional_resources_page()

render_persistent_music_overlay()
